"""Tool-calling accuracy evaluation for Experiment A.

Parses <tool_call>{JSON}</tool_call> from model output and compares
against ground-truth tool calls using BFCL-style AST sub-tree matching.
Normalizes all tool-call formats to canonical JSON before scoring (Risk R6).
"""

from __future__ import annotations

import json
import re
from dataclasses import dataclass, field
from typing import Any

import structlog

logger = structlog.get_logger(__name__)

# Patterns for parsing tool calls from model output
_TOOL_CALL_PATTERN = re.compile(
    r"<tool_call>\s*(\{.*?\})\s*</tool_call>", re.DOTALL
)
_HERMES_PATTERN = re.compile(
    r'<\|tool_call\|>\s*(\{.*?\})\s*(?:<\|/tool_call\|>|$)', re.DOTALL
)


@dataclass
class TurnPrediction:
    """A single turn's predicted tool calls."""

    turn_id: int
    content: str
    tool_calls: list[dict[str, Any]] = field(default_factory=list)


@dataclass
class TurnGroundTruth:
    """A single turn's expected tool calls."""

    turn_id: int
    tool_calls: list[dict[str, Any]] = field(default_factory=list)


@dataclass
class ToolCallMetrics:
    """Metrics for tool-calling evaluation."""

    tool_name_accuracy: float = 0.0  # Target: >=90%
    argument_exact_match: float = 0.0  # Target: >=75%
    tool_call_f1: float = 0.0  # Target: >=85%
    hallucinated_tool_rate: float = 0.0  # Target: <=3%
    # error_recovery_rate is tracked in StateMachineMetrics (recovery_rate), not here.

    def to_dict(self) -> dict[str, float]:
        return {
            "tool_name_accuracy": self.tool_name_accuracy,
            "argument_exact_match": self.argument_exact_match,
            "tool_call_f1": self.tool_call_f1,
            "hallucinated_tool_rate": self.hallucinated_tool_rate,
        }


def parse_tool_calls(content: str) -> list[dict[str, Any]]:
    """Parse tool calls from model output in various formats.

    Supports:
      - <tool_call>{JSON}</tool_call>
      - <|tool_call|>{JSON}<|/tool_call|>
      - Raw JSON with 'name' and 'arguments' fields

    Returns:
        List of normalized tool call dicts with 'name' and 'arguments'.
    """
    calls: list[dict[str, Any]] = []

    # Try standard format
    for match in _TOOL_CALL_PATTERN.finditer(content):
        try:
            parsed = json.loads(match.group(1))
            calls.append(_normalize_tool_call(parsed))
        except json.JSONDecodeError:
            continue

    if calls:
        return calls

    # Try Hermes format
    for match in _HERMES_PATTERN.finditer(content):
        try:
            parsed = json.loads(match.group(1))
            calls.append(_normalize_tool_call(parsed))
        except json.JSONDecodeError:
            continue

    return calls


def _normalize_tool_call(raw: dict[str, Any]) -> dict[str, Any]:
    """Normalize a tool call dict to canonical format.

    Handles variations like:
      - {"name": "fn", "arguments": {...}}
      - {"function": {"name": "fn", "arguments": {...}}}
      - {"name": "fn", "parameters": {...}}
    """
    if "function" in raw and isinstance(raw["function"], dict):
        fn = raw["function"]
        return {
            "name": fn.get("name", ""),
            "arguments": fn.get("arguments", fn.get("parameters", {})),
        }

    name = raw.get("name", "")
    arguments = raw.get("arguments", raw.get("parameters", {}))

    # If arguments is a JSON string, parse it
    if isinstance(arguments, str):
        try:
            arguments = json.loads(arguments)
        except json.JSONDecodeError:
            pass

    return {"name": name, "arguments": arguments}


def compute_name_accuracy(
    predicted: list[dict[str, Any]],
    ground_truth: list[dict[str, Any]],
) -> float:
    """Compute tool name accuracy (exact match of function name)."""
    if not ground_truth:
        return 1.0 if not predicted else 0.0

    correct = 0
    for i, gt in enumerate(ground_truth):
        if i < len(predicted) and predicted[i]["name"] == gt["name"]:
            correct += 1

    return correct / len(ground_truth)


def compute_argument_match(
    predicted: dict[str, Any],
    ground_truth: dict[str, Any],
) -> bool:
    """Check if predicted arguments exactly match ground truth.

    Uses recursive comparison for nested structures.
    """
    pred_args = predicted.get("arguments", {})
    gt_args = ground_truth.get("arguments", {})
    return _deep_equals(pred_args, gt_args)


def _deep_equals(a: Any, b: Any) -> bool:
    """Deep equality comparison for JSON-compatible values."""
    if type(a) is not type(b):
        # Allow int/float comparison
        if isinstance(a, (int, float)) and isinstance(b, (int, float)):
            return a == b
        return False
    if isinstance(a, dict):
        if set(a.keys()) != set(b.keys()):
            return False
        return all(_deep_equals(a[k], b[k]) for k in a)
    if isinstance(a, list):
        if len(a) != len(b):
            return False
        return all(_deep_equals(x, y) for x, y in zip(a, b))
    return a == b


def compute_ast_f1(
    predicted: list[dict[str, Any]],
    ground_truth: list[dict[str, Any]],
) -> float:
    """Compute BFCL-style AST sub-tree matching F1 score.

    A predicted tool call matches a ground-truth call if:
      - The function name matches exactly
      - All ground-truth argument key-value pairs are present in prediction
        (prediction may have extra keys — sub-tree match)
    """
    if not ground_truth and not predicted:
        return 1.0
    if not ground_truth or not predicted:
        return 0.0

    matched_gt: set[int] = set()
    matched_pred: set[int] = set()

    for pi, pred in enumerate(predicted):
        for gi, gt in enumerate(ground_truth):
            if gi in matched_gt:
                continue
            if pred["name"] == gt["name"] and _is_subtree_match(pred, gt):
                matched_pred.add(pi)
                matched_gt.add(gi)
                break

    tp = len(matched_gt)
    precision = tp / len(predicted) if predicted else 0.0
    recall = tp / len(ground_truth) if ground_truth else 0.0

    if precision + recall == 0:
        return 0.0
    return 2 * precision * recall / (precision + recall)


def _is_subtree_match(predicted: dict[str, Any], ground_truth: dict[str, Any]) -> bool:
    """Check if all ground-truth argument fields are present and correct in prediction."""
    gt_args = ground_truth.get("arguments", {})
    pred_args = predicted.get("arguments", {})

    if not isinstance(gt_args, dict) or not isinstance(pred_args, dict):
        return _deep_equals(gt_args, pred_args)

    for key, gt_val in gt_args.items():
        if key not in pred_args:
            return False
        if not _deep_equals(pred_args[key], gt_val):
            return False
    return True


def detect_hallucinated_tools(
    predicted: list[dict[str, Any]],
    valid_tool_names: list[str],
) -> list[str]:
    """Detect tool calls to tools not in the schema."""
    valid_set = set(valid_tool_names)
    return [tc["name"] for tc in predicted if tc["name"] not in valid_set]


def evaluate_tool_calls(
    predictions: list[TurnPrediction],
    ground_truth: list[TurnGroundTruth],
    tool_schemas: list[dict[str, Any]] | None = None,
) -> ToolCallMetrics:
    """Evaluate tool-calling accuracy across turns.

    Args:
        predictions: Per-turn model predictions.
        ground_truth: Per-turn expected tool calls.
        tool_schemas: Available tool schemas for hallucination detection.

    Returns:
        ToolCallMetrics with all computed metrics.
    """
    gt_map = {gt.turn_id: gt for gt in ground_truth}

    total_name_acc = 0.0
    total_arg_match = 0
    total_arg_comparisons = 0
    total_f1 = 0.0
    total_hallucinated = 0
    total_predicted = 0
    n_turns_with_tools = 0

    # Extract valid tool names from schemas
    valid_names: list[str] = []
    if tool_schemas:
        for schema in tool_schemas:
            fn = schema.get("function", schema)
            name = fn.get("name", "")
            if name:
                valid_names.append(name)

    for pred in predictions:
        gt = gt_map.get(pred.turn_id)
        if gt is None:
            continue

        pred_calls = pred.tool_calls or parse_tool_calls(pred.content)
        gt_calls = gt.tool_calls

        if not gt_calls and not pred_calls:
            continue

        n_turns_with_tools += 1
        total_predicted += len(pred_calls)

        # Name accuracy
        total_name_acc += compute_name_accuracy(pred_calls, gt_calls)

        # Argument exact match
        for i, gt_call in enumerate(gt_calls):
            total_arg_comparisons += 1
            if i < len(pred_calls) and compute_argument_match(pred_calls[i], gt_call):
                total_arg_match += 1

        # AST F1
        total_f1 += compute_ast_f1(pred_calls, gt_calls)

        # Hallucination detection
        if valid_names:
            hallucinated = detect_hallucinated_tools(pred_calls, valid_names)
            total_hallucinated += len(hallucinated)

    if n_turns_with_tools == 0:
        return ToolCallMetrics()

    metrics = ToolCallMetrics(
        tool_name_accuracy=total_name_acc / n_turns_with_tools,
        argument_exact_match=(
            total_arg_match / total_arg_comparisons if total_arg_comparisons > 0 else 0.0
        ),
        tool_call_f1=total_f1 / n_turns_with_tools,
        hallucinated_tool_rate=(
            total_hallucinated / total_predicted if total_predicted > 0 else 0.0
        ),
    )

    logger.info("tool_call_eval_complete", turns=n_turns_with_tools, **metrics.to_dict())
    return metrics

"""Tool chain propagation evaluation for Experiment A.

Evaluates whether return values from tool N correctly populate
arguments of tool N+1 in multi-step tool chains. Tracks per-depth
accuracy to identify where propagation breaks down.
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

import structlog

from llm_workflow_agents.eval.tool_call_f1 import parse_tool_calls

logger = structlog.get_logger(__name__)


@dataclass
class ChainPropagationMetrics:
    """Metrics for tool chain propagation evaluation."""

    chain_propagation_accuracy: float = 0.0  # Target: >=70%
    per_depth_accuracy: dict[int, float] = field(default_factory=dict)
    total_chains: int = 0  # Number of chain links evaluated; 0 means no chains present

    def to_dict(self) -> dict[str, Any]:
        return {
            "chain_propagation_accuracy": self.chain_propagation_accuracy,
            "per_depth_accuracy": self.per_depth_accuracy,
            "total_chains": self.total_chains,
        }


@dataclass
class ToolChainLink:
    """A single link in a tool chain: tool call followed by tool response."""

    tool_name: str
    arguments: dict[str, Any]
    response: dict[str, Any]
    depth: int


def extract_tool_chains(messages: list[dict[str, Any]]) -> list[ToolChainLink]:
    """Extract sequential tool chain links from a conversation.

    A chain link is: assistant tool_call → tool response → next assistant tool_call.
    """
    links: list[ToolChainLink] = []
    depth = 0

    i = 0
    while i < len(messages):
        msg = messages[i]

        if msg.get("role") == "assistant":
            calls = parse_tool_calls(msg.get("content", ""))
            if not calls:
                # Also check annotations
                annotations = msg.get("annotations", {})
                ann_calls = annotations.get("tool_calls", [])
                if ann_calls:
                    calls = ann_calls

            for call in calls:
                # Look for the corresponding tool response
                tool_response = _find_next_tool_response(messages, i + 1)
                if tool_response is not None:
                    links.append(
                        ToolChainLink(
                            tool_name=call.get("name", ""),
                            arguments=call.get("arguments", {}),
                            response=tool_response,
                            depth=depth + 1,  # 1-indexed: first call is depth 1
                        )
                    )
                    depth += 1

        i += 1

    return links


def _find_next_tool_response(messages: list[dict[str, Any]], start: int) -> dict[str, Any] | None:
    """Find the next tool response message starting from index.

    Stops at the next assistant message boundary to avoid associating a tool
    response from a later exchange with the current tool call.
    """
    for i in range(start, len(messages)):
        role = messages[i].get("role")
        if role == "tool":
            content = messages[i].get("content", "")
            try:
                return json.loads(content)
            except json.JSONDecodeError:
                return {"raw": content}
        elif role == "assistant":
            # Stop searching once a new assistant turn begins
            break
    return None


def check_value_propagation(
    prev_response: dict[str, Any],
    next_arguments: dict[str, Any],
) -> bool:
    """Check if any value from the previous tool response appears in the next tool's arguments.

    This is a heuristic check: at least one value from the response should
    appear as a value in the next call's arguments for the chain to be
    considered properly propagated.
    """
    if not prev_response or not next_arguments:
        return False

    response_values = _extract_leaf_values(prev_response)
    argument_values = _extract_leaf_values(next_arguments)

    # Check if any response value appears in the arguments
    return bool(response_values & argument_values)


def _extract_leaf_values(obj: Any, _values: set[str] | None = None) -> set[str]:
    """Extract all leaf string/number values from a nested structure."""
    if _values is None:
        _values = set()

    if isinstance(obj, dict):
        for v in obj.values():
            _extract_leaf_values(v, _values)
    elif isinstance(obj, list):
        for item in obj:
            _extract_leaf_values(item, _values)
    elif isinstance(obj, (str, int, float)) and obj != "":
        _values.add(str(obj))

    return _values


def evaluate_chain_propagation(
    predictions: list[dict[str, Any]],
    ground_truth: list[dict[str, Any]],
) -> ChainPropagationMetrics:
    """Evaluate tool chain propagation accuracy.

    Args:
        predictions: List of conversation prediction dicts with 'messages'.
        ground_truth: List of conversation ground-truth dicts with 'messages'.

    Returns:
        ChainPropagationMetrics with overall and per-depth accuracy.
    """
    depth_correct: dict[int, int] = {}
    depth_total: dict[int, int] = {}
    total_correct = 0
    total_chains = 0

    for pred, gt in zip(predictions, ground_truth):
        pred_links = extract_tool_chains(pred.get("messages", []))
        gt_links = extract_tool_chains(gt.get("messages", []))

        # Evaluate consecutive links: check whether predicted arguments at position i
        # contain values from the ground-truth previous tool response.
        # This validates that the model propagates the *correct* values, not just
        # that it stays internally self-consistent.
        n_pairs = min(len(pred_links), len(gt_links))
        for i in range(1, n_pairs):
            prev_gt = gt_links[i - 1]   # Ground-truth previous tool response
            curr_pred = pred_links[i]   # Predicted next tool call arguments
            depth = min(curr_pred.depth, 4)  # Cap at 4+ for grouping

            depth_total[depth] = depth_total.get(depth, 0) + 1
            total_chains += 1

            if check_value_propagation(prev_gt.response, curr_pred.arguments):
                depth_correct[depth] = depth_correct.get(depth, 0) + 1
                total_correct += 1

    per_depth: dict[int, float] = {}
    for d in sorted(depth_total.keys()):
        per_depth[d] = depth_correct.get(d, 0) / depth_total[d]

    metrics = ChainPropagationMetrics(
        chain_propagation_accuracy=total_correct / max(total_chains, 1),
        per_depth_accuracy=per_depth,
        total_chains=total_chains,
    )

    logger.info("chain_propagation_eval_complete", **metrics.to_dict())
    return metrics

